import * as React from "react"
import { cn } from "@/lib/utils"

const SYMBOLS: Record<string, string> = {
  cmd: "⌘", ctrl: "⌃", alt: "⌥", shift: "⇧",
  enter: "↵", esc: "⎋", tab: "⇥", del: "⌫",
  up: "↑", down: "↓", left: "←", right: "→",
}

interface KbdProps extends React.HTMLAttributes<HTMLElement> {
  keys: string[]
}

export function Kbd({ keys, className }: KbdProps) {
  return (
    <span className={cn("inline-flex items-center gap-0.5", className)}>
      {keys.map((k, i) => (
        <kbd
          key={i}
          className="inline-flex items-center justify-center rounded border border-white/[0.1] bg-white/[0.06] px-1.5 py-0.5 font-mono text-[11px] text-[#888] shadow-[inset_0_-1px_0_rgba(255,255,255,0.08)]"
        >
          {SYMBOLS[k.toLowerCase()] ?? k.toUpperCase()}
        </kbd>
      ))}
    </span>
  )
}
